/// <summary>
/// Size import
/// </summary>
public class ETG_Acu_EcoResSizeImport extends ETG_Acu_DataImportBase
{
}

Method.Source:
public static void main(Args args)
{
    ETG_Acu_EcoResSizeImport  sizeImport;

    sizeImport = ETG_Acu_EcoResSizeImport::construct();

    if (sizeImport.prompt())
    {
        sizeImport.runOperation();
    }
}

public static ETG_Acu_EcoResSizeImport construct()
{
    return new ETG_Acu_EcoResSizeImport();
}

/// <summary>
/// Describes whether the class is designed for execution in a new session.
/// </summary>
/// <returns>
/// true if the class is designed for execution the operation in a new session; otherwise, false.
/// </returns>
protected boolean canRunInNewSession()
{
    return false;
}

protected void processData(container _con)
{
    EcoResProductSizeEntity    size;

    size.SizeId   = conpeek(_con, 1);
    size.insert();
}

/// <summary>
/// Import colors
/// </summary>
/// <returns>Caption</returns>
public ClassDescription caption()
{
    ClassDescription ret;

    ret = "@ETG_ENG_Labels:ImpSize";

    return ret;
}
